import './MonthlyExpenseChart.css';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer
} from "recharts";

function MonthlyExpenseChart({monthlyData}){
    return (
        <>
        <ResponsiveContainer>
            <LineChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Line
                    type="monotone"
                    dataKey="expense"
                />
            </LineChart>
        </ResponsiveContainer>
        </>
    );
}
export default MonthlyExpenseChart;
